import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import api from '../api';
import './Forms.css';

const BLOOD_GROUPS = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'];

export default function RegisterDonor() {
  const { register, handleSubmit, setValue, watch, formState: { errors } } = useForm({
    defaultValues: { available: true, health_eligible: true }
  });
  const navigate = useNavigate();
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const [existing, setExisting] = useState(null);

  const available = watch('available');
  const health_eligible = watch('health_eligible');

  useEffect(() => {
    api.get('/profile').then(res => {
      const d = res.data.donor;
      if (d) {
        setExisting(d);
        setValue('blood_group', d.blood_group);
        setValue('last_donation_date', d.last_donation_date || '');
        setValue('available', d.available === 1);
        setValue('health_eligible', d.health_eligible === 1);
        setValue('latitude', d.latitude || '');
        setValue('longitude', d.longitude || '');
      }
    }).catch(() => {});
  }, [setValue]);

  const onSubmit = async (data) => {
    setError(''); setSuccess('');
    setLoading(true);
    try {
      await api.post('/register-donor', {
        ...data,
        available: data.available ? 1 : 0,
        health_eligible: data.health_eligible ? 1 : 0,
        latitude: data.latitude ? parseFloat(data.latitude) : null,
        longitude: data.longitude ? parseFloat(data.longitude) : null,
      });
      setSuccess(existing ? 'Donor profile updated successfully!' : 'Donor registered successfully!');
      setTimeout(() => navigate('/dashboard'), 1500);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to save donor profile.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page-container">
      <h1 className="page-title">🩸 {existing ? 'Update Donor Profile' : 'Register as Donor'}</h1>

      <div className="form-card card">
        {error   && <div className="alert alert-error">{error}</div>}
        {success && <div className="alert alert-success">{success}</div>}

        <form onSubmit={handleSubmit(onSubmit)}>
          <div className="grid-2">
            <div className="form-group">
              <label>Blood Group *</label>
              <select {...register('blood_group', { required: 'Blood group is required' })}>
                <option value="">Select blood group</option>
                {BLOOD_GROUPS.map(g => <option key={g} value={g}>{g}</option>)}
              </select>
              {errors.blood_group && <span className="error">{errors.blood_group.message}</span>}
            </div>

            <div className="form-group">
              <label>Last Donation Date</label>
              <input type="date" {...register('last_donation_date')} max={new Date().toISOString().split('T')[0]} />
            </div>
          </div>

          <div className="grid-2">
            <div className="form-group">
              <label>Latitude (optional)</label>
              <input type="number" step="any" placeholder="e.g. 40.7128" {...register('latitude')} />
              <span className="field-hint">For distance-based matching</span>
            </div>
            <div className="form-group">
              <label>Longitude (optional)</label>
              <input type="number" step="any" placeholder="e.g. -74.0060" {...register('longitude')} />
            </div>
          </div>

          <div className="toggle-section">
            <div className="toggle-row">
              <label className="toggle">
                <input type="checkbox" {...register('available')} />
                <span className="toggle-slider" />
              </label>
              <div>
                <span className="toggle-label">Available to Donate</span>
                <span className="toggle-desc">{available ? 'You are currently available' : 'You are not available'}</span>
              </div>
            </div>

            <div className="toggle-row">
              <label className="toggle">
                <input type="checkbox" {...register('health_eligible')} />
                <span className="toggle-slider" />
              </label>
              <div>
                <span className="toggle-label">Health Eligible</span>
                <span className="toggle-desc">{health_eligible ? 'I confirm I am medically eligible to donate' : 'Not eligible at this time'}</span>
              </div>
            </div>
          </div>

          <div className="form-actions">
            <button type="button" className="btn btn-secondary" onClick={() => navigate('/dashboard')}>Cancel</button>
            <button type="submit" className="btn btn-primary" disabled={loading}>
              {loading ? <span className="spinner" /> : (existing ? 'Update Profile' : 'Register Donor')}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}
